const random = Math.random();
let path = 'noticias';
if (random > 0.7) {
  path = 'obras';
} else if (random > 0.4) {
  path = 'educativo';
}
return [{ json: { path: path } }];

const items = $input.all();
if (items.length === 0) {
  return [{ json: { tema: "Manutenção Preventiva de Portaria", tipo: "educativo", produto_dl: "DL Fortress", comentario_tecnico: "Comentário da DL: Manter a infraestrutura de controle de acesso ativa sob contrato recorrente." } }];
}
const randomIndex = Math.floor(Math.random() * items.length);
const item = items[randomIndex].json;

// Mapeia produto baseado no titulo
const text = (item.title + " " + (item.contentSnippet || "")).toLowerCase();
let produto = "DL Partner";
if (text.includes("solar") || text.includes("energia")) produto = "DL EcoVolt";
else if (text.includes("câmera") || text.includes("segurança") || text.includes("roubo")) produto = "DL Guardião";
else if (text.includes("fogo") || text.includes("incêndio")) produto = "DL Alerta";
else if (text.includes("bomba") || text.includes("caixa d")) produto = "DL Acqua";
else if (text.includes("portão") || text.includes("acesso")) produto = "DL Gatekeeper";

return [{
  json: {
    tema: item.title,
    tipo: "noticias",
    fonte_nome: "RSS Feed",
    fonte_url: item.link,
    resumo: item.contentSnippet || item.content,
    produto_dl: produto,
    comentario_tecnico: "Comentário da DL: A tecnologia aplicada ao condomínio reduz perdas de segurança. Recomenda-se Avaliação Técnica de " + produto
  }
}];

const temas = [
  { tema: "Importância da Manutenção Elétrica Predial no Inverno", produto: "DL Volt", comentario: "Avaliação periódica em quadros elétricos previne sobrecargas no inverno." },
  { tema: "Como a Portaria Autônoma reduz custos operacionais", produto: "DL Fortress", comentario: "A tecnologia Fortress reduz custos com portarias físicas mantendo rastreabilidade." },
  { tema: "Vantagens do Backup de Energia Híbrido em Condomínios", produto: "DL EcoVolt", comentario: "Economia com economia de ponta e continuidade para portões e CFTV." }
];
const selected = temas[Math.floor(Math.random() * temas.length)];
return [{
  json: {
    tema: selected.tema,
    tipo: "educativo",
    fonte_nome: "DL Educativo",
    produto_dl: selected.produto,
    comentario_tecnico: selected.comentario
  }
}];
